import type { ArtifactSectionEnvelope } from '../../../shared/contracts/index.js';
import {
  appendSectionMessage,
  createSectionElement,
  renderSectionEnvelopeState,
} from './section-envelope.js';

export function renderArtifactSection(args: {
  envelope: ArtifactSectionEnvelope | null;
  targetDocument: Document;
}): HTMLElement {
  if (args.envelope === null || args.envelope.status !== 'ready') {
    return renderSectionEnvelopeState({
      title: 'Artifacts',
      envelope: args.envelope,
      targetDocument: args.targetDocument,
    });
  }

  const section = createSectionElement({
    title: 'Artifacts',
    targetDocument: args.targetDocument,
  });
  const list = args.targetDocument.createElement('ul');

  if (args.envelope.items.length === 0) {
    return appendSectionMessage({
      section,
      message: 'No artifacts yet.',
      targetDocument: args.targetDocument,
    });
  }

  for (const artifact of args.envelope.items) {
    const item = args.targetDocument.createElement('li');
    const heading = args.targetDocument.createElement('strong');
    const revision = args.targetDocument.createElement('p');
    const scope = args.targetDocument.createElement('p');
    const updatedAt = args.targetDocument.createElement('p');

    heading.textContent = artifact.displayName;
    revision.textContent =
      artifact.currentVersionLabel === null
        ? 'No current version available.'
        : `Current version: ${artifact.currentVersionLabel}`;
    scope.textContent =
      artifact.attachmentScope === 'project'
        ? 'Project-scoped artifact.'
        : `Attached to ${artifact.processDisplayLabel ?? artifact.processId ?? 'a process'}.`;
    updatedAt.textContent = `Updated: ${artifact.updatedAt}`;

    item.append(heading, revision, scope, updatedAt);
    list.append(item);
  }

  section.append(list);
  return section;
}

import type { SourceAttachmentSectionEnvelope } from '../../../shared/contracts/index.js';
import {
  appendSectionMessage,
  createSectionElement,
  renderSectionEnvelopeState,
} from './section-envelope.js';

function formatHydrationStateLabel(hydrationState: string): string {
  return hydrationState.replaceAll('_', ' ');
}

export function renderSourceAttachmentSection(args: {
  envelope: SourceAttachmentSectionEnvelope | null;
  targetDocument: Document;
}): HTMLElement {
  if (args.envelope === null || args.envelope.status !== 'ready') {
    return renderSectionEnvelopeState({
      title: 'Source attachments',
      envelope: args.envelope,
      targetDocument: args.targetDocument,
    });
  }

  const section = createSectionElement({
    title: 'Source attachments',
    targetDocument: args.targetDocument,
  });
  const list = args.targetDocument.createElement('ul');

  if (args.envelope.items.length === 0) {
    return appendSectionMessage({
      section,
      message: 'No source attachments yet.',
      targetDocument: args.targetDocument,
    });
  }

  for (const sourceAttachment of args.envelope.items) {
    const item = args.targetDocument.createElement('li');
    const heading = args.targetDocument.createElement('strong');
    const purpose = args.targetDocument.createElement('p');
    const hydration = args.targetDocument.createElement('p');
    const scope = args.targetDocument.createElement('p');
    const updatedAt = args.targetDocument.createElement('p');

    heading.textContent = sourceAttachment.displayName;
    purpose.textContent = `Purpose: ${sourceAttachment.purpose}`;
    hydration.textContent = `Hydration: ${formatHydrationStateLabel(sourceAttachment.hydrationState)}`;
    scope.textContent =
      sourceAttachment.attachmentScope === 'project'
        ? 'Project-scoped source attachment.'
        : `Attached to ${sourceAttachment.processDisplayLabel ?? sourceAttachment.processId ?? 'a process'}.`;
    updatedAt.textContent = `Updated: ${sourceAttachment.updatedAt}`;

    item.append(heading, purpose, hydration, scope, updatedAt);

    if (sourceAttachment.targetRef !== null) {
      const targetRef = args.targetDocument.createElement('p');
      targetRef.textContent = `Target ref: ${sourceAttachment.targetRef}`;
      item.append(targetRef);
    }

    list.append(item);
  }

  section.append(list);
  return section;
}

import type {
  ArtifactSectionEnvelope,
  ProcessSectionEnvelope,
  SourceAttachmentSectionEnvelope,
} from '../../../shared/contracts/index.js';

type AnyEnvelope =
  | ProcessSectionEnvelope
  | ArtifactSectionEnvelope
  | SourceAttachmentSectionEnvelope
  | null;

export function createSectionElement(args: {
  title: string;
  targetDocument: Document;
}): HTMLElement {
  const section = args.targetDocument.createElement('section');
  const title = args.targetDocument.createElement('h2');
  title.textContent = args.title;
  section.append(title);
  return section;
}

export function appendSectionMessage(args: {
  section: HTMLElement;
  message: string;
  targetDocument: Document;
}): HTMLElement {
  const body = args.targetDocument.createElement('p');
  body.textContent = args.message;
  args.section.append(body);
  return args.section;
}

export function renderSectionEnvelopeState(args: {
  title: string;
  envelope: AnyEnvelope;
  targetDocument: Document;
}): HTMLElement {
  const section = createSectionElement(args);

  if (args.envelope === null) {
    return appendSectionMessage({
      section,
      message: `Loading ${args.title.toLowerCase()}...`,
      targetDocument: args.targetDocument,
    });
  }

  if (args.envelope.status === 'empty') {
    return appendSectionMessage({
      section,
      message: `${args.title} is currently empty.`,
      targetDocument: args.targetDocument,
    });
  }

  if (args.envelope.status === 'error') {
    return appendSectionMessage({
      section,
      message: args.envelope.error?.message ?? `${args.title} failed to load.`,
      targetDocument: args.targetDocument,
    });
  }

  return appendSectionMessage({
    section,
    message: `${args.title} ready with ${args.envelope.items.length} item(s).`,
    targetDocument: args.targetDocument,
  });
}
